    if 'id' in option_attrs:
        option_attrs['id'] = self.id_for_label(option_attrs['id'], index)
    return {
        'name': name,
        'value': value,
        'label': label,
        'selected': selected,
        'index': index,
        'attrs': option_attrs,
        'type': self.input_type,
