def __init__(self, terminalwriter, *args, **kwargs):
    super(ColoredLevelFormatter, self).__init__(*args, **kwargs)
    if six.PY2:
        self._original_fmt = self._fmt
    else:
        self._original_fmt = self._style._fmt
    self._level_to_fmt_mapping = {}

    levelname_fmt_match = self.LEVELNAME_FMT_REGEX.search(self._fmt)
    if not levelname_fmt_match:
        return
    levelname_fmt = levelname_fmt_match.group()

    for level, color_opts in self.LOGLEVEL_COLOROPTS.items():
        formatted_levelname = levelname_fmt % {
            "levelname": logging.getLevelName(level)
        }

        # add ANSI escape sequences around the formatted levelname
        color_kwargs = {name: True for name in color_opts}
        colorized_formatted_levelname = terminalwriter.markup(
            formatted_levelname, **color_kwargs
        )
        self._level_to_fmt_mapping[level] = self.LEVELNAME_FMT_REGEX.sub(
            colorized_formatted_levelname, self._fmt
        )

def format(self, record):
    fmt = self._level_to_fmt_mapping.get(record.levelno, self._original_fmt)
    if six.PY2:
        self._fmt = fmt
    else:
        self._style._fmt = fmt
    return super(ColoredLevelFormatter, self).format(record)

def getini(self, name):
    """ return configuration value from an :ref:`ini file <inifiles>`. If the
    specified name hasn't been registered through a prior
    :py:func:`parser.addini <_pytest.config.Parser.addini>`
    call (usually from a plugin), a ValueError is raised. """
    try:
        return self._inicache[name]
    except KeyError:
        self._inicache[name] = val = self._getini(name)
        return val

def _getini(self, name):
    try:
        description, type, default = self._parser._inidict[name]
    except KeyError:
        raise ValueError("unknown configuration value: %r" % (name,))
    value = self._get_override_ini_value(name)
    if value is None:
        try:
            value = self.inicfg[name]
        except KeyError:
            if default is not None:
                return default
            if type is None:
                return ""
            return []
    if type == "pathlist":
        dp = py.path.local(self.inicfg.config.path).dirpath()
        values = []
        for relpath in shlex.split(value):
            values.append(dp.join(relpath, abs=True))
        return values
    elif type == "args":
        return shlex.split(value)
    elif type == "linelist":
        return [t for t in map(lambda x: x.strip(), value.split("\n")) if t]
    elif type == "bool":
        return bool(_strtobool(value.strip()))
    else:
        assert type is None
        return value

def _get_override_ini_value(self, name):
    value = None
    # override_ini is a list of "ini=value" options
    # always use the last item if multiple values are set for same ini-name,
    # e.g. -o foo=bar1 -o foo=bar2 will set foo to bar2
    for ini_config in self._override_ini:
        try:
            key, user_ini_value = ini_config.split("=", 1)
        except ValueError:
            raise UsageError("-o/--override-ini expects option=value style.")
        else:
            if key == name:
                value = user_ini_value
    return value

def _processopt(self, opt):
    for name in opt._short_opts + opt._long_opts:
        self._opt2dest[name] = opt.dest

    if hasattr(opt, "default") and opt.dest:
        if not hasattr(self.option, opt.dest):
            setattr(self.option, opt.dest, opt.default)

def _pprint_estimator(self, object, stream, indent, allowance, context,
                      level):
    stream.write(object.__class__.__name__ + '(')
    if self._indent_at_name:
        indent += len(object.__class__.__name__)

    if self._changed_only:
        params = _changed_params(object)
    else:
        params = object.get_params(deep=False)

    params = OrderedDict((name, val)
                         for (name, val) in sorted(params.items()))

    self._format_params(params.items(), stream, indent, allowance + 1,
                        context, level)
    stream.write(')')

def _format_dict_items(self, items, stream, indent, allowance, context,
                       level):
    return self._format_params_or_dict_items(
        items, stream, indent, allowance, context, level, is_dict=True)

def prepare_docstring(s: str, ignore: int = None, tabsize: int = 8) -> List[str]:
    """Convert a docstring into lines of parseable reST.  Remove common leading
    indentation, where the indentation of a given number of lines (usually just
    one) is ignored.

    Return the docstring as a list of lines usable for inserting into a docutils
    ViewList (used as argument of nested_parse().)  An empty line is added to
    act as a separator between this docstring and following content.
    """
    if ignore is None:
        ignore = 1
    else:
        warnings.warn("The 'ignore' argument to parepare_docstring() is deprecated.",
                      RemovedInSphinx50Warning, stacklevel=2)

    lines = s.expandtabs(tabsize).splitlines()
    # Find minimum indentation of any non-blank lines after ignored lines.
    margin = sys.maxsize
    for line in lines[ignore:]:
        content = len(line.lstrip())
        if content:
            indent = len(line) - content
            margin = min(margin, indent)
    # Remove indentation from ignored lines.
    for i in range(ignore):
        if i < len(lines):
            lines[i] = lines[i].lstrip()
    if margin < sys.maxsize:
        for i in range(ignore, len(lines)):
            lines[i] = lines[i][margin:]
    # Remove any leading blank lines.
    while lines and not lines[0]:
        lines.pop(0)
    # make sure there is an empty line at the end
    if lines and lines[-1]:
        lines.append('')
    return lines

def _parse_attributes_section(self, section: str) -> List[str]:
    lines = []
    for _name, _type, _desc in self._consume_fields():
        if self._config.napoleon_use_ivar:
            _name = self._qualify_name(_name, self._obj)
            field = ':ivar %s: ' % _name
            lines.extend(self._format_block(field, _desc))
            if _type:
                lines.append(':vartype %s: %s' % (_name, _type))
        else:
            lines.append('.. attribute:: ' + _name)
            if self._opt and 'noindex' in self._opt:
                lines.append('   :noindex:')
            if _type:
                lines.extend(self._indent([':type: %s' % _type], 3))
            lines.append('')

            fields = self._format_field('', '', _desc)
            lines.extend(self._indent(fields, 3))
            lines.append('')
    if self._config.napoleon_use_ivar:
        lines.append('')
    return lines

def _format_block(self, prefix: str, lines: List[str], padding: str = None) -> List[str]:
    if lines:
        if padding is None:
            padding = ' ' * len(prefix)
        result_lines = []
        for i, line in enumerate(lines):
            if i == 0:
                result_lines.append((prefix + line).rstrip())
            elif line:
                result_lines.append(padding + line)
            else:
                result_lines.append('')
        return result_lines
    else:
        return [prefix]

def _consume_fields(self, parse_type: bool = True, prefer_type: bool = False
                    ) -> List[Tuple[str, str, List[str]]]:
    self._consume_empty()
    fields = []
    while not self._is_section_break():
        _name, _type, _desc = self._consume_field(parse_type, prefer_type)
        if _name or _type or _desc:
            fields.append((_name, _type, _desc,))
    return fields

def _escape_args_and_kwargs(self, name: str) -> str:
    if name.endswith('_'):
        name = name[:-1] + r'\_'

    if name[:2] == '**':
        return r'\*\*' + name[2:]
    elif name[:1] == '*':
        return r'\*' + name[1:]
    else:
        return name

def _partition_field_on_colon(self, line: str) -> Tuple[str, str, str]:
    before_colon = []
    after_colon = []
    colon = ''
    found_colon = False
    for i, source in enumerate(_xref_or_code_regex.split(line)):
        if found_colon:
            after_colon.append(source)
        else:
            m = _single_colon_regex.search(source)
            if (i % 2) == 0 and m:
                found_colon = True
                colon = source[m.start(): m.end()]
                before_colon.append(source[:m.start()])
                after_colon.append(source[m.end():])
            else:
                before_colon.append(source)

    return ("".join(before_colon).strip(),
            colon,
            "".join(after_colon).strip())

def _strip_empty(self, lines: List[str]) -> List[str]:
    if lines:
        start = -1
        for i, line in enumerate(lines):
            if line:
                start = i
                break
        if start == -1:
            lines = []
        end = -1
        for i in reversed(range(len(lines))):
            line = lines[i]
            if line:
                end = i
                break
        if start > 0 or end + 1 < len(lines):
            lines = lines[start:end + 1]
    return lines

def a2idx(j, n=None):
    """Return integer after making positive and validating against n."""
    if type(j) is not int:
        try:
            j = j.__index__()
        except AttributeError:
            raise IndexError("Invalid index a[%r]" % (j,))
    if n is not None:
        if j < 0:
            j += n
        if not (j >= 0 and j < n):
            raise IndexError("Index out of range: a[%s]" % (j,))
    return int(j)

def _eval_extract(self, rowsList, colsList):
    urow = list(uniq(rowsList))
    ucol = list(uniq(colsList))
    smat = {}
    if len(urow)*len(ucol) < len(self._smat):
        # there are fewer elements requested than there are elements in the matrix
        for i, r in enumerate(urow):
            for j, c in enumerate(ucol):
                smat[i, j] = self._smat.get((r, c), 0)
    else:
        # most of the request will be zeros so check all of self's entries,
        # keeping only the ones that are desired
        for rk, ck in self._smat:
            if rk in urow and ck in ucol:
                smat[(urow.index(rk), ucol.index(ck))] = self._smat[(rk, ck)]

    rv = self._new(len(urow), len(ucol), smat)
    # rv is nominally correct but there might be rows/cols
    # which require duplication
    if len(rowsList) != len(urow):
        for i, r in enumerate(rowsList):
            i_previous = rowsList.index(r)
            if i_previous != i:
                rv = rv.row_insert(i, rv.row(i_previous))
    if len(colsList) != len(ucol):
        for i, c in enumerate(colsList):
            i_previous = colsList.index(c)
            if i_previous != i:
                rv = rv.col_insert(i, rv.col(i_previous))
    return rv

def __getitem__(self, key):

    if isinstance(key, tuple):
        i, j = key
        try:
            i, j = self.key2ij(key)
            return self._smat.get((i, j), S.Zero)
        except (TypeError, IndexError):
            if isinstance(i, slice):
                # XXX remove list() when PY2 support is dropped
                i = list(range(self.rows))[i]
            elif is_sequence(i):
                pass
            elif isinstance(i, Expr) and not i.is_number:
                from sympy.matrices.expressions.matexpr import MatrixElement
                return MatrixElement(self, i, j)
            else:
                if i >= self.rows:
                    raise IndexError('Row index out of bounds')
                i = [i]
            if isinstance(j, slice):
                # XXX remove list() when PY2 support is dropped
                j = list(range(self.cols))[j]
            elif is_sequence(j):
                pass
            elif isinstance(j, Expr) and not j.is_number:
                from sympy.matrices.expressions.matexpr import MatrixElement
                return MatrixElement(self, i, j)
            else:
                if j >= self.cols:
                    raise IndexError('Col index out of bounds')
                j = [j]
            return self.extract(i, j)

    # check for single arg, like M[:] or M[3]
    if isinstance(key, slice):
        lo, hi = key.indices(len(self))[:2]
        L = []
        for i in range(lo, hi):
            m, n = divmod(i, self.cols)
            L.append(self._smat.get((m, n), S.Zero))
        return L

    i, j = divmod(a2idx(key, len(self)), self.cols)
    return self._smat.get((i, j), S.Zero)

def _print_Function(self, expr, exp=None):
    r'''
    Render functions to LaTeX, handling functions that LaTeX knows about
    e.g., sin, cos, ... by using the proper LaTeX command (\sin, \cos, ...).
    For single-letter function names, render them as regular LaTeX math
    symbols. For multi-letter function names that LaTeX does not know
    about, (e.g., Li, sech) use \operatorname{} so that the function name
    is rendered in Roman font and LaTeX handles spacing properly.

    expr is the expression involving the function
    exp is an exponent
    '''
    func = expr.func.__name__
    if hasattr(self, '_print_' + func) and \
        not isinstance(expr.func, UndefinedFunction):
        return getattr(self, '_print_' + func)(expr, exp)
    else:
        args = [ str(self._print(arg)) for arg in expr.args ]
        # How inverse trig functions should be displayed, formats are:
        # abbreviated: asin, full: arcsin, power: sin^-1
        inv_trig_style = self._settings['inv_trig_style']
        # If we are dealing with a power-style inverse trig function
        inv_trig_power_case = False
        # If it is applicable to fold the argument brackets
        can_fold_brackets = self._settings['fold_func_brackets'] and \
            len(args) == 1 and \
            not self._needs_function_brackets(expr.args[0])

        inv_trig_table = ["asin", "acos", "atan", "acot"]

        # If the function is an inverse trig function, handle the style
        if func in inv_trig_table:
            if inv_trig_style == "abbreviated":
                func = func
            elif inv_trig_style == "full":
                func = "arc" + func[1:]
            elif inv_trig_style == "power":
                func = func[1:]
                inv_trig_power_case = True

                # Can never fold brackets if we're raised to a power
                if exp is not None:
                    can_fold_brackets = False

        if inv_trig_power_case:
            if func in accepted_latex_functions:
                name = r"\%s^{-1}" % func
            else:
                name = r"\operatorname{%s}^{-1}" % func
        elif exp is not None:
            name = r'%s^{%s}' % (self._hprint_Function(func), exp)
        else:
            name = self._hprint_Function(func)

        if can_fold_brackets:
            if func in accepted_latex_functions:
                # Wrap argument safely to avoid parse-time conflicts
                # with the function name itself
                name += r" {%s}"
            else:
                name += r"%s"
        else:
            name += r"{\left (%s \right )}"

        if inv_trig_power_case and exp is not None:
            name += r"^{%s}" % exp

        return name % ",".join(args)

def _hprint_Function(self, func):
    r'''
    Logic to decide how to render a function to latex
      - if it is a recognized latex name, use the appropriate latex command
      - if it is a single letter, just use that letter
      - if it is a longer name, then put \operatorname{} around it and be
        mindful of undercores in the name
    '''
    func = self._deal_with_super_sub(func)
    if func in accepted_latex_functions:
        name = r"\%s" % func
    elif len(func) == 1 or func.startswith('\\'):
        name = func
    else:
        name = r"\operatorname{%s}" % func
    return name

def _print_FunctionClass(self, expr):
    for cls in self._special_function_classes:
        if issubclass(expr, cls) and expr.__name__ == cls.__name__:
            return self._special_function_classes[cls]
    return self._hprint_Function(str(expr))

def as_base_exp(self):
    # a -> b ** e
    return self, S.One

def _collect_factor_and_dimension(self, expr):
    """
    Return tuple with scale factor expression and dimension expression.
    """
    from sympy.physics.units import Quantity
    if isinstance(expr, Quantity):
        return expr.scale_factor, expr.dimension
    elif isinstance(expr, Mul):
        factor = 1
        dimension = Dimension(1)
        for arg in expr.args:
            arg_factor, arg_dim = self._collect_factor_and_dimension(arg)
            factor *= arg_factor
            dimension *= arg_dim
        return factor, dimension
    elif isinstance(expr, Pow):
        factor, dim = self._collect_factor_and_dimension(expr.base)
        exp_factor, exp_dim = self._collect_factor_and_dimension(expr.exp)
        if self.get_dimension_system().is_dimensionless(exp_dim):
            exp_dim = 1
        return factor ** exp_factor, dim ** (exp_factor * exp_dim)
    elif isinstance(expr, Add):
        factor, dim = self._collect_factor_and_dimension(expr.args[0])
        for addend in expr.args[1:]:
            addend_factor, addend_dim = \
                self._collect_factor_and_dimension(addend)
            if dim != addend_dim:
                raise ValueError(
                    'Dimension of "{}" is {}, '
                    'but it should be {}'.format(
                        addend, addend_dim, dim))
            factor += addend_factor
        return factor, dim
    elif isinstance(expr, Derivative):
        factor, dim = self._collect_factor_and_dimension(expr.args[0])
        for independent, count in expr.variable_count:
            ifactor, idim = self._collect_factor_and_dimension(independent)
            factor /= ifactor**count
            dim /= idim**count
        return factor, dim
    elif isinstance(expr, Function):
        fds = [self._collect_factor_and_dimension(arg) for arg in expr.args]
        dims = [Dimension(1) if self.get_dimension_system().is_dimensionless(d[1]) else d[1] for d in fds]
        return (expr.func(*(f[0] for f in fds)), *dims)
    elif isinstance(expr, Dimension):
        return S.One, expr
    else:
        return expr, Dimension(1)

def get_dimensional_dependencies(self, name, mark_dimensionless=False):
    dimdep = self._get_dimensional_dependencies_for_name(name)
    if mark_dimensionless and dimdep == {}:
        return {Dimension(1): 1}
    return {k: v for k, v in dimdep.items()}

def _get_dimensional_dependencies_for_name(self, dimension):
    if isinstance(dimension, str):
        dimension = Dimension(Symbol(dimension))
    elif not isinstance(dimension, Dimension):
        dimension = Dimension(dimension)

    if dimension.name.is_Symbol:
        # Dimensions not included in the dependencies are considered
        # as base dimensions:
        return dict(self.dimensional_dependencies.get(dimension, {dimension: 1}))

    if dimension.name.is_number or dimension.name.is_NumberSymbol:
        return {}

    get_for_name = self._get_dimensional_dependencies_for_name

    if dimension.name.is_Mul:
        ret = collections.defaultdict(int)
        dicts = [get_for_name(i) for i in dimension.name.args]
        for d in dicts:
            for k, v in d.items():
                ret[k] += v
        return {k: v for (k, v) in ret.items() if v != 0}

    if dimension.name.is_Add:
        dicts = [get_for_name(i) for i in dimension.name.args]
        if all(d == dicts[0] for d in dicts[1:]):
            return dicts[0]
        raise TypeError("Only equivalent dimensions can be added or subtracted.")

    if dimension.name.is_Pow:
        dim_base = get_for_name(dimension.name.base)
        dim_exp = get_for_name(dimension.name.exp)
        if dim_exp == {} or dimension.name.exp.is_Symbol:
            return {k: v * dimension.name.exp for (k, v) in dim_base.items()}
        else:
            raise TypeError("The exponent for the power operator must be a Symbol or dimensionless.")

    if dimension.name.is_Function:
        args = (Dimension._from_dimensional_dependencies(
            get_for_name(arg)) for arg in dimension.name.args)
        result = dimension.name.func(*args)

        dicts = [get_for_name(i) for i in dimension.name.args]

        if isinstance(result, Dimension):
            return self.get_dimensional_dependencies(result)
        elif result.func == dimension.name.func:
            if isinstance(dimension.name, TrigonometricFunction):
                if dicts[0] in ({}, {Dimension('angle'): 1}):
                    return {}
                else:
                    raise TypeError("The input argument for the function {} must be dimensionless or have dimensions of angle.".format(dimension.func))
            else:
                if all(item == {} for item in dicts):
                    return {}
                else:
                    raise TypeError("The input arguments for the function {} must be dimensionless.".format(dimension.func))
        else:
            return get_for_name(result)

    raise TypeError("Type {} not implemented for get_dimensional_dependencies".format(type(dimension.name)))

def get_quantity_dimension(self, unit):
    qdm = self.get_dimension_system()._quantity_dimension_map
    if unit in qdm:
        return qdm[unit]
    return super().get_quantity_dimension(unit)

def get_quantity_scale_factor(self, unit):
    qsfm = self.get_dimension_system()._quantity_scale_factors
    if unit in qsfm:
        return qsfm[unit]
    return super().get_quantity_scale_factor(unit)

def dim(self):
    """
    Give the dimension of the system.

    That is return the number of units forming the basis.
    """
    return len(self._base_units)
